import { Segmented, Compare } from "@faraday-academy/kit/blocks";

export function CompareModes() {
  const [mode, setMode] = useState("elastic");
  return (
    <>
      <Segmented
        label="Collision type"
        value={mode}
        onChange={setMode}
        options={[
          { value: "elastic", label: "Elastic" },
          { value: "inelastic", label: "Inelastic" },
        ]}
      />
      <Compare
        items={[
          { value: "elastic", label: "Elastic", content: "KE conserved" },
          { value: "inelastic", label: "Inelastic", content: "KE not conserved" },
        ]}
      />
    </>
  );
}

import { Prose, Quiz } from "@faraday-academy/kit/blocks";

export function McqCheck() {
  return (
    <>
      <Prose heading="Momentum is conserved when…">
        Think about which forces are internal to the system you chose.
      </Prose>
      <Quiz
        question="When is momentum conserved?"
        options={[
          { label: "No external force", correct: true },
          { label: "Always", hint: "Only in a closed system." },
        ]}
      />
    </>
  );
}

import { Derivation, NumericAnswer } from "@faraday-academy/kit/blocks";

export function NumericGate() {
  return (
    <>
      <Derivation
        title="Impulse"
        steps={[
          { tex: "J = F \\Delta t", note: "Definition" },
          { tex: "J = \\Delta p", note: "Equals change in momentum" },
        ]}
      />
      <NumericAnswer
        question="A 2 kg cart moves at 3 m/s. What is its momentum?"
        answer={6}
        tolerance={0.1}
        unit="kg·m/s"
      />
    </>
  );
}

import {
  Workbench,
  ControlGroup,
  ParamSlider,
  Readout,
} from "@faraday-academy/kit/blocks";

export function ParamLab() {
  const [mass, setMass] = useState(3);
  const [vel, setVel] = useState(4);
  return (
    <Workbench
      title="Momentum"
      panelTitle="Parameters"
      controls={
        <ControlGroup label="Inputs">
          <ParamSlider label="Mass (kg)" value={mass} min={1} max={10} onChange={setMass} />
          <ParamSlider label="Velocity (m/s)" value={vel} min={0} max={10} onChange={setVel} />
        </ControlGroup>
      }
    >
      <Readout label="p = m·v" value={`${(mass * vel).toFixed(1)} kg·m/s`} />
    </Workbench>
  );
}
